 	NewStatus string `json:"new_status,omitempty"`
 }

+// isCloseEvent returns true if the event represents an issue being closed.
+func (e bdActivityEvent) isCloseEvent() bool {
+	return e.Type == "status" && e.NewStatus == "closed"
+}
